/// <summary>
/// Storage backend for the sync engine. Implementations may be a local folder
/// (testing), or a network drive / S3 / WebDAV in production.
///
/// Exported over FFI (`with_foreign`) so a host language can inject its own
/// backend. uniFFI requires owned argument types (`String`/`Vec<u8>`, not
/// slices) and forbids tuple returns, so signatures use owned values and the
/// [`ClientStatus`] record instead of `(String, u64)`.
/// </summary>
internal interface RemoteStorage {
    /// <summary>
    /// List all oplog objects for a file.
    /// </summary>
    /// <exception cref="SyncException"></exception>
    RemoteLogItem[] ListOplogs(string @fileId);
    /// <summary>
    /// Append an oplog entry unconditionally, overwriting any object with the
    /// same `{sequence}_{client_id}` name.
    /// </summary>
    /// <exception cref="SyncException"></exception>
    void PutOplog(string @fileId, OpLogEntry @entry);
    /// <summary>
    /// Compare-and-swap append: fail with [`SyncError::Conflict`] if *any*
    /// client already published this sequence. Underpins CAS-retry.
    /// </summary>
    /// <exception cref="SyncException"></exception>
    void PutOplogCas(string @fileId, OpLogEntry @entry);
    /// <summary>
    /// Fetch the raw bytes of an oplog object by its remote-relative path.
    /// </summary>
    /// <exception cref="SyncException"></exception>
    byte[] GetOplog(string @fileId, string @remotePath);
    /// <summary>
    /// Delete an oplog object.
    /// </summary>
    /// <exception cref="SyncException"></exception>
    void DeleteOplog(string @fileId, string @remotePath);
    /// <summary>
    /// Store a content-addressed chunk. Idempotent: writing an existing hash is
    /// a no-op success.
    /// </summary>
    /// <exception cref="SyncException"></exception>
    void PutChunk(string @hash, byte[] @data);
    /// <summary>
    /// Fetch a chunk's bytes by hash.
    /// </summary>
    /// <exception cref="SyncException"></exception>
    byte[] GetChunk(string @hash);
    /// <summary>
    /// Delete a chunk by hash.
    /// </summary>
    /// <exception cref="SyncException"></exception>
    void DeleteChunk(string @hash);
    /// <summary>
    /// List all stored chunk hashes (for garbage collection).
    /// </summary>
    /// <exception cref="SyncException"></exception>
    string[] ListChunks();
    /// <summary>
    /// Store a compressed baseline snapshot for a file at a given sequence.
    /// </summary>
    /// <exception cref="SyncException"></exception>
    void PutBaseline(string @fileId, ulong @seq, byte[] @data);
    /// <summary>
    /// Fetch a baseline snapshot, if present.
    /// </summary>
    /// <exception cref="SyncException"></exception>
    byte[]? GetBaseline(string @fileId, ulong @seq);
    /// <summary>
    /// List available baseline sequences for a file, ascending.
    /// </summary>
    /// <exception cref="SyncException"></exception>
    ulong[] ListBaselines(string @fileId);
    /// <summary>
    /// Publish this client's synced-progress marker.
    /// </summary>
    /// <exception cref="SyncException"></exception>
    void PutStatus(string @clientId, ulong @lastSyncedSequence);
    /// <summary>
    /// Read every client's progress marker.
    /// </summary>
    /// <exception cref="SyncException"></exception>
    ClientStatus[] ListStatuses();
}
