        return new ChunkInfo(
            @hash: FfiConverterString.INSTANCE.Read(stream),
            @offset: FfiConverterUInt64.INSTANCE.Read(stream),
            @length: FfiConverterUInt32.INSTANCE.Read(stream)
        );
