        return 0
            + FfiConverterUInt64.INSTANCE.AllocationSize(value.@sequence)
            + FfiConverterString.INSTANCE.AllocationSize(value.@clientId)
            + FfiConverterString.INSTANCE.AllocationSize(value.@remotePath);
    }

    public override void Write(RemoteLogItem value, BigEndianStream stream) {
            FfiConverterUInt64.INSTANCE.Write(value.@sequence, stream);
            FfiConverterString.INSTANCE.Write(value.@clientId, stream);
            FfiConverterString.INSTANCE.Write(value.@remotePath, stream);
    }
