/// <summary>
/// How to resolve a genuine content conflict between two binary versions.
/// </summary>
internal enum BinaryConflictPolicy: int {
    
    /// <summary>
    /// Discard the remote version, keep the local one.
    /// </summary>
    KeepLocal,
    /// <summary>
    /// Discard the local version, keep the remote one.
    /// </summary>
    KeepRemote,
    /// <summary>
    /// Keep both; the host is asked to duplicate one side under a new name.
    /// </summary>
    KeepBoth
}

class FfiConverterTypeBinaryConflictPolicy: FfiConverterRustBuffer<BinaryConflictPolicy> {
    public static FfiConverterTypeBinaryConflictPolicy INSTANCE = new FfiConverterTypeBinaryConflictPolicy();

    public override BinaryConflictPolicy Read(BigEndianStream stream) {
        var value = stream.ReadInt() - 1;
        if (Enum.IsDefined(typeof(BinaryConflictPolicy), value)) {
            return (BinaryConflictPolicy)value;
        } else {
            throw new InternalException(String.Format("invalid enum value '{0}' in FfiConverterTypeBinaryConflictPolicy.Read()", value));
        }
    }

    public override int AllocationSize(BinaryConflictPolicy value) {
        return 4;
    }

    public override void Write(BinaryConflictPolicy value, BigEndianStream stream) {
        stream.WriteInt((int)value + 1);
    }
}







/// <summary>
/// The payload of a single change recorded in an [`OpLogEntry`].
/// </summary>
internal record ChangeType {
    
    /// <summary>
    /// A yrs (y-crdt) update, v1-encoded.
    /// </summary>
    public record TextDelta (
        byte[] @delta
    ) : ChangeType {}
    
    /// <summary>
    /// The full chunk manifest of a binary file at this version.
    /// </summary>
    public record BinarySnapshot (
        string[] @chunkHashes
    ) : ChangeType {}
    
    /// <summary>
    /// The file was deleted at this version.
    /// </summary>
    public record Delete: ChangeType {}
    
    

    
}

class FfiConverterTypeChangeType : FfiConverterRustBuffer<ChangeType>{
    public static FfiConverterRustBuffer<ChangeType> INSTANCE = new FfiConverterTypeChangeType();

    public override ChangeType Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1:
                return new ChangeType.TextDelta(
                    FfiConverterByteArray.INSTANCE.Read(stream)
                );
            case 2:
                return new ChangeType.BinarySnapshot(
                    FfiConverterSequenceString.INSTANCE.Read(stream)
                );
            case 3:
                return new ChangeType.Delete(
                );
            default:
                throw new InternalException(String.Format("invalid enum value '{0}' in FfiConverterTypeChangeType.Read()", value));
        }
    }

    public override int AllocationSize(ChangeType value) {
        switch (value) {
            case ChangeType.TextDelta variant_value:
                return 4
                    + FfiConverterByteArray.INSTANCE.AllocationSize(variant_value.@delta);
            case ChangeType.BinarySnapshot variant_value:
                return 4
                    + FfiConverterSequenceString.INSTANCE.AllocationSize(variant_value.@chunkHashes);
            case ChangeType.Delete variant_value:
                return 4;
            default:
                throw new InternalException(String.Format("invalid enum value '{0}' in FfiConverterTypeChangeType.AllocationSize()", value));
        }
    }

    public override void Write(ChangeType value, BigEndianStream stream) {
        switch (value) {
            case ChangeType.TextDelta variant_value:
                stream.WriteInt(1);
                FfiConverterByteArray.INSTANCE.Write(variant_value.@delta, stream);
                break;
            case ChangeType.BinarySnapshot variant_value:
                stream.WriteInt(2);
                FfiConverterSequenceString.INSTANCE.Write(variant_value.@chunkHashes, stream);
                break;
            case ChangeType.Delete variant_value:
                stream.WriteInt(3);
                break;
            default:
                throw new InternalException(String.Format("invalid enum value '{0}' in FfiConverterTypeChangeType.Write()", value));
        }
    }
}







/// <summary>
/// Errors crossing the FFI boundary.
/// </summary>
internal class SyncException: UniffiException {
    SyncException() : base() {}
    SyncException(String @Message) : base(@Message) {}

    // Each variant is a nested class
    
    /// <summary>
    /// An I/O or storage-backend failure.
    /// </summary>
    
    public class IoException : SyncException {
        // Members
        public string @msg;

        // Constructor
        public IoException(
                string @msg) : base(
                "@msg" + "=" + @msg) {

            this.@msg = @msg;
        }
    }
    
    /// <summary>
    /// A binary conflict requires a host-supplied policy decision.
    /// </summary>
    
    public class ConflictNeedResolution : SyncException {
        public ConflictNeedResolution() : base() {}
    }
    
    
    /// <summary>
    /// A CAS append lost a race with a concurrent writer at the same sequence.
    /// </summary>
    
    public class Conflict : SyncException {
        // Members
        public ulong @sequence;

        // Constructor
        public Conflict(
                ulong @sequence) : base(
                "@sequence" + "=" + @sequence) {

            this.@sequence = @sequence;
        }
    }
    
    /// <summary>
    /// The bounded CAS-retry loop gave up.
    /// </summary>
    
    public class RetryExhausted : SyncException {
        // Members
        public uint @attempts;

        // Constructor
        public RetryExhausted(
                uint @attempts) : base(
                "@attempts" + "=" + @attempts) {

            this.@attempts = @attempts;
        }
    }
    
    /// <summary>
    /// A stored blob failed to (de)serialize.
    /// </summary>
    
    public class SerdeException : SyncException {
        // Members
        public string @msg;

        // Constructor
        public SerdeException(
                string @msg) : base(
                "@msg" + "=" + @msg) {

            this.@msg = @msg;
        }
    }
    

    
}

class FfiConverterTypeSyncError : FfiConverterRustBuffer<SyncException>, CallStatusErrorHandler<SyncException> {
    public static FfiConverterTypeSyncError INSTANCE = new FfiConverterTypeSyncError();

    public override SyncException Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1:
                return new SyncException.IoException(
                    FfiConverterString.INSTANCE.Read(stream));
            case 2:
                return new SyncException.ConflictNeedResolution();
            case 3:
                return new SyncException.Conflict(
                    FfiConverterUInt64.INSTANCE.Read(stream));
            case 4:
                return new SyncException.RetryExhausted(
                    FfiConverterUInt32.INSTANCE.Read(stream));
            case 5:
                return new SyncException.SerdeException(
                    FfiConverterString.INSTANCE.Read(stream));
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypeSyncError.Read()", value));
        }
    }

    public override int AllocationSize(SyncException value) {
        switch (value) {

            case SyncException.IoException variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@msg);

            case SyncException.ConflictNeedResolution variant_value:
                return 4;

            case SyncException.Conflict variant_value:
                return 4
                    + FfiConverterUInt64.INSTANCE.AllocationSize(variant_value.@sequence);

            case SyncException.RetryExhausted variant_value:
                return 4
                    + FfiConverterUInt32.INSTANCE.AllocationSize(variant_value.@attempts);

            case SyncException.SerdeException variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@msg);
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypeSyncError.AllocationSize()", value));
        }
    }

    public override void Write(SyncException value, BigEndianStream stream) {
        switch (value) {
            case SyncException.IoException variant_value:
                stream.WriteInt(1);
                FfiConverterString.INSTANCE.Write(variant_value.@msg, stream);
                break;
            case SyncException.ConflictNeedResolution variant_value:
                stream.WriteInt(2);
                break;
            case SyncException.Conflict variant_value:
                stream.WriteInt(3);
                FfiConverterUInt64.INSTANCE.Write(variant_value.@sequence, stream);
                break;
            case SyncException.RetryExhausted variant_value:
                stream.WriteInt(4);
                FfiConverterUInt32.INSTANCE.Write(variant_value.@attempts, stream);
                break;
            case SyncException.SerdeException variant_value:
                stream.WriteInt(5);
                FfiConverterString.INSTANCE.Write(variant_value.@msg, stream);
                break;
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypeSyncError.Write()", value));
        }
    }
}




